import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Login from './pages/Login';
import Home from './pages/Home';
import PatientLogin from './pages/PatientLogin';
import PatientRegister from './pages/PatientRegister';
import PatientDashboard from './pages/PatientDashboard';
import Appointments from './pages/Appointments';
import Queue from './pages/Queue';
import Triage from './pages/Triage';
import Consultation from './pages/Consultation';
import Prescriptions from './pages/Prescriptions';
import LabTests from './pages/LabTests';
import auth from './services/auth';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const currentUser = auth.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
    setLoading(false);
  }, []);

  const handleLogout = () => {
    auth.logout();
    setUser(null);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-4 border-blue-500 mx-auto mb-4"></div>
          <p className="text-xl text-gray-700 font-semibold">Loading Clinic Management System...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {/* Public Routes */}
        <Route path="/" element={<Home />} />
        <Route path="/home" element={<Home />} />
        <Route path="/patient-login" element={!user ? <PatientLogin /> : <Navigate to="/patient-dashboard" />} />
        <Route path="/patient-register" element={!user ? <PatientRegister /> : <Navigate to="/patient-dashboard" />} />
        <Route path="/login" element={!user ? <Login onLogin={setUser} /> : <Navigate to="/dashboard" />} />

        {/* Patient Dashboard */}
        <Route 
          path="/patient-dashboard" 
          element={user ? <PatientDashboard patient={user} onLogout={handleLogout} /> : <Navigate to="/patient-login" />} 
        />

        {/* Staff Dashboard Routes */}
        {user ? (
          <>
            <Route path="/dashboard" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Dashboard userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/appointments" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Appointments userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/queue" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Queue userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/triage" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Triage userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/consultation" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Consultation userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/prescriptions" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <Prescriptions userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/lab-orders" element={
              <div className="flex h-screen bg-gray-50">
                <Sidebar userRole={user.role} />
                <div className="flex-1 flex flex-col overflow-hidden">
                  <Header user={user} onLogout={handleLogout} />
                  <main className="flex-1 overflow-auto bg-gray-50">
                    <LabTests userRole={user.role} />
                  </main>
                </div>
              </div>
            } />

            <Route path="/" element={<Navigate to="/dashboard" />} />
          </>
        ) : (
          <Route path="*" element={<Navigate to="/home" />} />
        )}
      </Routes>
    </Router>
  );
}

export default App;
